import debug from "debug";
var logger = debug("open-attestation");
export var getLogger = function (namespace) { return ({
    trace: logger.extend("trace:".concat(namespace)),
    debug: logger.extend("debug:".concat(namespace)),
    info: logger.extend("info:".concat(namespace)),
    warn: logger.extend("warn:".concat(namespace)),
    error: logger.extend("error:".concat(namespace)),
}); };
